-- Verificar si la tabla existe
DO $$ 
DECLARE
    table_exists BOOLEAN;
BEGIN
    -- Verificar si la tabla existe
    SELECT EXISTS (
        SELECT FROM information_schema.tables 
        WHERE table_name = 'chat_buffer'
    ) INTO table_exists;

    IF table_exists THEN
        -- Tabla existe, agregar columnas faltantes
        RAISE NOTICE 'La tabla chat_buffer ya existe. Agregando columnas faltantes...';

        -- Agregar 'processed' si no existe
        IF NOT EXISTS (
            SELECT 1 FROM information_schema.columns 
            WHERE table_name = 'chat_buffer' AND column_name = 'processed'
        ) THEN
            ALTER TABLE chat_buffer ADD COLUMN processed BOOLEAN DEFAULT FALSE;
            RAISE NOTICE 'Columna "processed" agregada.';
        END IF;

        -- Agregar 'message_type' si no existe
        IF NOT EXISTS (
            SELECT 1 FROM information_schema.columns 
            WHERE table_name = 'chat_buffer' AND column_name = 'message_type'
        ) THEN
            ALTER TABLE chat_buffer ADD COLUMN message_type VARCHAR(50) DEFAULT 'text';
            RAISE NOTICE 'Columna "message_type" agregada.';
        END IF;

        -- Agregar 'phone_number' si no existe
        IF NOT EXISTS (
            SELECT 1 FROM information_schema.columns 
            WHERE table_name = 'chat_buffer' AND column_name = 'phone_number'
        ) THEN
            ALTER TABLE chat_buffer ADD COLUMN phone_number VARCHAR(50);
            RAISE NOTICE 'Columna "phone_number" agregada.';
        END IF;

        -- Crear índices si no existen
        IF NOT EXISTS (
            SELECT 1 FROM pg_indexes 
            WHERE tablename = 'chat_buffer' AND indexname = 'idx_chat_buffer_conversation_processed'
        ) THEN
            CREATE INDEX idx_chat_buffer_conversation_processed 
            ON chat_buffer(conversation_id, processed);
            RAISE NOTICE 'Índice "idx_chat_buffer_conversation_processed" creado.';
        END IF;

        IF NOT EXISTS (
            SELECT 1 FROM pg_indexes 
            WHERE tablename = 'chat_buffer' AND indexname = 'idx_chat_buffer_created_at'
        ) THEN
            CREATE INDEX idx_chat_buffer_created_at 
            ON chat_buffer(created_at);
            RAISE NOTICE 'Índice "idx_chat_buffer_created_at" creado.';
        END IF;

    ELSE
        -- Tabla no existe, crearla desde cero
        RAISE NOTICE 'Creando tabla chat_buffer...';

        CREATE TABLE chat_buffer (
            id SERIAL PRIMARY KEY,
            conversation_id INTEGER NOT NULL,
            message TEXT,
            message_type VARCHAR(50) DEFAULT 'text',
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            processed BOOLEAN DEFAULT FALSE,
            phone_number VARCHAR(50)
        );

        CREATE INDEX idx_chat_buffer_conversation_processed 
        ON chat_buffer(conversation_id, processed);

        CREATE INDEX idx_chat_buffer_created_at 
        ON chat_buffer(created_at);

        RAISE NOTICE 'Tabla chat_buffer creada exitosamente.';
    END IF;
END $$;

