// Parámetros
const phone = $('Mapeo').first().json.whatsapp_cliente;
const text = $('cliente_texto').first().json.texto;

// Formato del context_id para WhatsApp
const context_id = `${phone}`;

// Emitimos payload con el formato correcto
return [{
  json: {
    message: JSON.stringify({ text }),
    context_id: context_id
  }
}];

const msg = $json.message || '';
const wordCount = msg.split(/\s+/).filter(w => w).length;
const { minWords, waitLong, waitShort } = items[0].json;
const waitSeconds = wordCount < minWords ? waitShort : waitLong;
return [{ json: { context_id: $json.context_id, message: msg, waitSeconds } }];

// Run Once For All Items
const j = items[0].json;
const raw = Array.isArray(j.buffer) ? j.buffer : [];

// 1) Parsear cada entrada lo más flexible posible
const buffer = raw
  .map(x => {
    let obj;
    // Si viene como string JSON, lo parseo
    if (typeof x === 'string') {
      try {
        obj = JSON.parse(x);
      } catch {
        return null;
      }
    } else if (typeof x === 'object') {
      obj = x;
    } else {
      return null;
    }

    // 2) Extraer texto de message, sea string o anidado { text }
    let textVal;
    if (typeof obj.message === 'string') {
      textVal = obj.message;
    } else if (obj.message && typeof obj.message.text === 'string') {
      textVal = obj.message.text;
    } else {
      return null;
    }

    // 3) Validar timestamp
    if (!obj.timestamp) return null;

    return {
      text: textVal.trim(),
      timestamp: obj.timestamp,
    };
  })
  .filter(Boolean);

// 4) Orden cronológico
buffer.sort((a, b) => new Date(a.timestamp) - new Date(b.timestamp));

// 5) Dedupe y concatenar
const unique = [...new Set(buffer.map(m => m.text))];
const consolidated = unique.join(' ');

// 6) Devolver
return [{
  json: {
    context_id: j.context_id,
    message: consolidated,
  }
}];

// Obtenemos el mensaje agrupado
const rawMessage = $input.first().json.message;

// Usamos regex para extraer todos los valores de "text"
const textMatches = rawMessage.match(/"text":"([^"]*)"/g);

// Si encontramos matches, extraemos solo los valores
let cleanText = "";
if (textMatches) {
  const texts = textMatches.map(match => {
    // Extraemos el valor entre las comillas después de "text":"
    const value = match.match(/"text":"([^"]*)"/)[1];
    return value;
  });

  // Unimos todos los textos con un espacio
  cleanText = texts.join(" ");
}

// Retornamos el texto limpio
return [{
  json: {
    text: cleanText
  }
}];

