const output = $input.first().json.output;

const items = [];

// Array con el orden específico de las partes
const orden = ['parte1', 'parte2', 'parte3', 'parte4'];

// Iterar en el orden definido
for (const parte of orden) {
  const contenido = output[parte];

  // Filtrar null, undefined, string vacío, y string "null"
  if (contenido && 
      contenido !== null && 
      contenido !== undefined && 
      contenido !== 'null' && 
      contenido.trim() !== '') {
    items.push({
      json: {
        parte: parte,
        content: contenido
      }
    });
  }
}

return items;
